using Microsoft.AspNetCore.Components;
using Microsoft.JSInterop;

namespace sv_da71fda749c642f0bc40340c1e494876.Components;

/// <summary>
/// Non-generic helper that owns the JS IntersectionObserver and receives callbacks.
/// Used internally by <see cref="InfiniteScrollList{TItem}"/>.
/// </summary>
public sealed class InfiniteScrollInterop : IAsyncDisposable
{
    internal const string ModulePath = "./Components/InfiniteScrollList.razor.js";
    internal const string InitMethod = "initialize";
    internal const string DisposeMethod = "dispose";

    private readonly IJSRuntime _js;
    private readonly Func<Task> _onSentinelVisible;
    private IJSObjectReference? _module;
    private DotNetObjectReference<InfiniteScrollInterop>? _dotNetRef;

    public InfiniteScrollInterop(IJSRuntime js, Func<Task> onSentinelVisible)
    {
        _js = js;
        _onSentinelVisible = onSentinelVisible;
