arguments.old_str:
@using Microsoft.AspNetCore.Components
@using Microsoft.JSInterop
@inject IJSRuntime JS
@implements IAsyncDisposable
@typeparam TItem

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="infinite-scroll-sentinel">
            <div class="spinner-border text-secondary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
</div>

@code {
    private ElementReference _sentinelRef;
    private InfiniteScrollInterop? _interop;
    private DotNetObjectReference<InfiniteScrollList>? _dotNetRef;
    private bool _isLoading;

    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && HasMore)
        {
            _interop = new InfiniteScrollInterop(JS);
            _dotNetRef = DotNetObjectReference.Create(this);
            await _interop.InitializeAsync(_sentinelRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (_isLoading || !HasMore)
            return;

        _isLoading = true;

        await InvokeAsync(async () =>
        {
            await OnLoadMore.InvokeAsync();
            _isLoading = false;
            StateHasChanged();
        });
    }

    public async ValueTask DisposeAsync()
    {
        if (_interop is not null)
            await _interop.DisposeAsync();

        _dotNetRef?.Dispose();
    }
}

